/**
 * Prop extension for the loading state on the DataTable.
 * @public
 */
export interface DataTableLoadingStateProps {
    /**
     * Displays a loading indicator while the table's columns and/or data are being loaded.
     *
     * @defaultValue false
     */
    loading?: boolean;
}
/**
 * Extension interface to extend the tanstack table state with the loading state.
 * @internal
 */
export interface DataTableLoadingState {
    /**
     * Table state extension for loading state
     */
    loading?: boolean;
}
